import { ActionPageSubmissionForm } from '@pages/ActionPages/pages/PublicActionPage/ActionPageView/utils/getActionPageInitialValues/getActionPageInitialValues';
import valid from 'card-validator';
import { useEffect, useMemo, useState } from 'react';
import { useFormContext } from 'react-hook-form';
import { useTranslation } from 'react-i18next';
import { FormAddressControl } from '../../../AddressControl/FormAddressControl';
import { FormSingleCheckboxControl } from '../../../CheckboxControl/FormSingleCheckboxControl';
import { FormGroup, FormGroupProps } from '../../../FormGroup';
import { FormInputControl } from '../../../FormInputControl';
import { FormMaskedInputControl } from '../../../MaskedInputControl';

export type ICreditCardForm = {
  cardZip?: string;
  city: string;
  country: string;
  cvv: string;
  expDate: string;
  line1: string;
  line2: string;
  name: string;
  postalCode: string;
  region: string;
  usePrevAddress: boolean;
  vaultToken: string;
};

interface IProps {
  additionalAction?: React.ReactNode;
  addressIsRequired?: boolean;
  cardZipRequired?: boolean;
  cvvRequired?: boolean;
  formGroupProps?: Omit<FormGroupProps, 'children'>;
  prevAddressText?: string;
  showBillingAddress?: boolean;
  showCardZip?: boolean;
  showCardholderName?: boolean;
  showTitle?: boolean;
}

export const CreditCardForm = ({
  additionalAction,
  addressIsRequired,
  cardZipRequired = false,
  cvvRequired = true,
  formGroupProps,
  prevAddressText,
  showBillingAddress = true,
  showCardholderName = true,
  showCardZip = false,
  showTitle = true,
}: IProps) => {
  const [hasTriggered, setHasTriggered] = useState(false);
  const { trigger, watch } = useFormContext<ActionPageSubmissionForm>();
  const cardNumber = watch('vaultToken');
  const usePrevAddress = watch('usePrevAddress');
  const country = watch('addressAttributes.country');
  const { t } = useTranslation('finance', { keyPrefix: 'commitments.paymentMethodForm' });

  const { card } = useMemo(() => valid.number(cardNumber), [cardNumber]);

  const cvcLabel = card?.code.name || 'CVC / CVV';

  // force trigger for cardzip whenever a vault value is entered
  useEffect(() => {
    if (cardNumber && cardNumber.length > 0 && !hasTriggered) {
      trigger('cardZip');
      setHasTriggered(true);
    }
  }, [cardNumber, trigger, hasTriggered]);

  return (
    <>
      <FormGroup
        {...formGroupProps}
        title={showTitle ? t('headings.creditCardInformation') : undefined}
      >
        <div className="items-stretch">
          <div className="flex flex-col">
            {showCardholderName ? (
              <FormInputControl
                autoComplete="cc-name"
                isRequired
                label={t('name.label')}
                name="name"
              />
            ) : null}
            <FormMaskedInputControl
              autoComplete="cc-number"
              creditCardType={card?.type}
              data-analytics-ignore
              isRequired
              label={t('vaultToken.label')}
              name="vaultToken"
              type="creditCard"
            />
            {cardNumber && (
              <div className="flex gap-2">
                <FormMaskedInputControl
                  autoComplete="cc-exp"
                  data-analytics-ignore
                  isRequired
                  label={t('expirationDate.label')}
                  name="expDate"
                  type="expiry"
                />
                <FormMaskedInputControl
                  autoComplete="cc-csc"
                  data-analytics-ignore
                  isRequired={cvvRequired}
                  label={cvcLabel}
                  name="cvv"
                  type="cvc"
                />
                {showCardZip ? (
                  <FormInputControl
                    autoComplete="postal-code"
                    isRequired={cardZipRequired}
                    label={country === 'US' || !country ? t('cardZip.label') : 'Postal Code'}
                    name="cardZip"
                    type="tel"
                  />
                ) : null}
              </div>
            )}
          </div>
          {additionalAction}
        </div>
      </FormGroup>
      {showBillingAddress && (
        <FormGroup {...formGroupProps} title={t('headings.billingAddress')}>
          {(!prevAddressText || (prevAddressText && !usePrevAddress)) && (
            <FormAddressControl isRequired={addressIsRequired} />
          )}
          {prevAddressText && (
            <FormSingleCheckboxControl name="usePrevAddress">
              {prevAddressText}
            </FormSingleCheckboxControl>
          )}
        </FormGroup>
      )}
    </>
  );
};

